package dev.harrison.rendacomcarro.finance.application;
import dev.harrison.rendacomcarro.finance.domain.*;import dev.harrison.rendacomcarro.finance.infrastructure.*;import dev.harrison.rendacomcarro.vehicle.application.VehicleService;import java.math.*;import java.time.LocalDate;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class FinancialObligationService {private final FinancialObligationRepository obligations;private final ObligationInstallmentRepository installments;private final ObligationPaymentRepository payments;private final VehicleService vehicles;private final InstallmentScheduleCalculator calculator;public FinancialObligationService(FinancialObligationRepository o,ObligationInstallmentRepository i,ObligationPaymentRepository p,VehicleService v,InstallmentScheduleCalculator c){obligations=o;installments=i;payments=p;vehicles=v;calculator=c;}
 public record CreateCommand(UUID vehicleId,ObligationType type,ObligationMode mode,String creditor,BigDecimal principal,BigDecimal annualRate,LocalDate startDate,LocalDate firstDueDate,Integer termMonths,BigDecimal plannedInstallment,BigDecimal monthlyTarget,String notes){}
 @Transactional public FinancialObligation create(CreateCommand c){var vehicle=c.vehicleId()==null?null:vehicles.get(c.vehicleId());var o=obligations.save(FinancialObligation.create(vehicle,c.type(),c.mode(),c.creditor(),c.principal(),c.annualRate(),c.startDate(),c.firstDueDate(),c.termMonths(),c.plannedInstallment(),c.monthlyTarget(),c.notes()));if(c.mode()==ObligationMode.STRUCTURED)calculator.calculate(c.principal(),c.annualRate()==null?BigDecimal.ZERO:c.annualRate(),c.termMonths(),c.firstDueDate()).forEach(e->installments.save(ObligationInstallment.create(o,e.sequence(),e.dueDate(),e.principal(),e.interest(),e.total())));return o;}
 @Transactional public ObligationPayment pay(UUID id,LocalDate date,BigDecimal principal,BigDecimal interest,BigDecimal extra,String ref,String notes){var o=get(id);if(ref!=null&&!ref.isBlank()&&payments.existsByObligationIdAndExternalReference(id,ref))throw new IllegalArgumentException("Pagamento duplicado");BigDecimal reduction=principal.add(extra);o.applyPrincipal(reduction);obligations.save(o);return payments.save(ObligationPayment.create(o,date,principal,interest,extra,ref,notes));}
 @Transactional(readOnly=true)public FinancialObligation get(UUID id){return obligations.findById(id).orElseThrow(()->new IllegalArgumentException("Obrigação não encontrada"));}@Transactional(readOnly=true)public List<FinancialObligation> list(){return obligations.findAllByOrderByCreatedAtDesc();}@Transactional(readOnly=true)public List<ObligationInstallment> schedule(UUID id){return installments.findAllByObligationIdOrderByDueDateAsc(id);}@Transactional(readOnly=true)public List<ObligationPayment> paymentHistory(UUID id){return payments.findAllByObligationIdOrderByPaymentDateDesc(id);}
}
